var results = $.steps.researchBrand.response.results || [];
var researchText = '';
results.forEach(function(r, i) {
  researchText += 'SOURCE ' + (i + 1) + ': ' + (r.title || '') + '\n';
  researchText += (r.text || '').slice(0, 1500) + '\n\n';
});
return { researchText: researchText, sourceCount: results.length };

var data = $.steps.compileResearch.output;
var prompt = 'You are a senior brand designer and visual identity specialist. Generate detailed logo design concepts for the following brand.

';
prompt += 'BRAND NAME: ' + $.input.brandName + '
';
prompt += 'DESCRIPTION: ' + $.input.brandDescription + '
';
if ($.input.designPreferences) prompt += 'PREFERENCES: ' + $.input.designPreferences + '
';
prompt += '
BRAND/INDUSTRY RESEARCH (' + data.sourceCount + ' sources):
' + data.researchText + '
';
prompt += 'INSTRUCTIONS:
';
prompt += '- Analyze the brand identity and competitive landscape
';
prompt += '- Generate 3 distinct logo concepts with different styles
';
prompt += '- For each concept: describe the visual, typography, color palette, and symbolism
';
prompt += '- Include a complete brand style guide
';
prompt += '- Provide detailed text-to-image prompts a designer could use

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "brandAnalysis": { "personality": "...", "values": ["..."], "targetAudience": "...", "competitorStyles": "..." },
';
prompt += '  "concepts": [
';
prompt += '    {
';
prompt += '      "name": "Concept name",
';
prompt += '      "style": "Modern|Classic|Playful|Minimal|Bold",
';
prompt += '      "description": "Detailed visual description",
';
prompt += '      "typography": "Font style recommendation",
';
prompt += '      "colors": { "primary": "#hex", "secondary": "#hex", "accent": "#hex" },
';
prompt += '      "symbolism": "What the design represents",
';
prompt += '      "imagePrompt": "Text-to-image prompt for generating this logo"
';
prompt += '    }
';
prompt += '  ],
';
prompt += '  "styleGuide": { "fonts": ["..."], "colorPalette": ["#hex"], "doNots": ["..."], "usageGuidelines": "..." }
';
prompt += '}';
return { prompt: prompt };

let raw = $.steps.aiDesign.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { brandAnalysis: {}, concepts: [], styleGuide: {} }; }

var ai = $.steps.parseAI.output;
var date = new Date().toISOString().split('T')[0];
var doc = '# Logo Design Brief: ' + $.input.brandName + '\n\n';
doc += '**Date:** ' + date + '\n\n';
var ba = ai.brandAnalysis || {};
if (ba.personality) {
  doc += '## Brand Analysis\n';
  doc += '- **Personality:** ' + ba.personality + '\n';
  doc += '- **Values:** ' + (ba.values || []).join(', ') + '\n';
  doc += '- **Target Audience:** ' + (ba.targetAudience || '') + '\n';
  doc += '- **Competitor Styles:** ' + (ba.competitorStyles || '') + '\n\n';
}
var concepts = ai.concepts || [];
concepts.forEach(function(c, i) {
  doc += '## Concept ' + (i + 1) + ': ' + (c.name || 'Untitled') + '\n';
  doc += '**Style:** ' + (c.style || '') + '\n\n';
  doc += c.description + '\n\n';
  doc += '**Typography:** ' + (c.typography || '') + '\n';
  if (c.colors) {
    doc += '**Colors:** Primary: ' + (c.colors.primary || '') + ', Secondary: ' + (c.colors.secondary || '') + ', Accent: ' + (c.colors.accent || '') + '\n';
  }
  doc += '**Symbolism:** ' + (c.symbolism || '') + '\n\n';
  doc += '**Image Prompt:** ' + (c.imagePrompt || '') + '\n\n';
});
var sg = ai.styleGuide || {};
if (sg.fonts || sg.colorPalette) {
  doc += '## Style Guide\n';
  if (sg.fonts) doc += '**Fonts:** ' + (sg.fonts || []).join(', ') + '\n';
  if (sg.colorPalette) doc += '**Color Palette:** ' + (sg.colorPalette || []).join(', ') + '\n';
  if (sg.doNots) doc += '**Do Nots:** ' + (sg.doNots || []).join(', ') + '\n';
  if (sg.usageGuidelines) doc += '**Usage:** ' + sg.usageGuidelines + '\n';
}
doc += '\n---\n*Generated with Claude AI via One CLI*\n';
var fileName = $.input.brandName.replace(/[^a-zA-Z0-9 ]/g, '') + ' - Logo Brief - ' + date + '.md';
return { document: doc, fileName: fileName, date: date, conceptCount: concepts.length };

var ai = $.steps.parseAI.output;
var doc = $.steps.buildDocument.output;
var concepts = ai.concepts || [];
var html = '<h2>Logo Design Brief: ' + $.input.brandName + '</h2>';
html += '<p><strong>Brand:</strong> ' + $.input.brandDescription + '</p>';
html += '<p><strong>Concepts Generated:</strong> ' + doc.conceptCount + '</p>';
html += '<hr>';
concepts.slice(0, 3).forEach(function(c, i) {
  html += '<h3>Concept ' + (i + 1) + ': ' + (c.name || '') + '</h3>';
  html += '<p><strong>Style:</strong> ' + (c.style || '') + '</p>';
  html += '<p>' + (c.description || '').slice(0, 300) + '</p>';
  if (c.colors) {
    html += '<p><strong>Colors:</strong> ' + (c.colors.primary || '') + ', ' + (c.colors.secondary || '') + ', ' + (c.colors.accent || '') + '</p>';
  }
});
html += '<hr><p><small>Full brief saved to Google Drive: ' + doc.fileName + '</small></p>';
var subject = 'Logo Design Brief: ' + $.input.brandName;
return { subject: subject, htmlBody: html.slice(0, 1900) };
